import{_ as s,o as n,c as a,f as e}from"./app-55c326ac.js";const t={},p=e(`<h1 id="history配置" tabindex="-1"><a class="header-anchor" href="#history配置" aria-hidden="true">#</a> history配置</h1><p>在生产环境下，记录某个命令的执行时间是很有必要的，但默认history只记录命令的序号和命令内容，不记录时间和使用者，所以需要对history进行相关的配置。<br> 在进行相关配置的时候，需要知道用户目录下的环境变量和全局环境变量，一个是对全局生效，一个是对当前用户生效， 当前用户的环境变量：<code>~/.bashrc</code> <code>~/.bash_profile</code><br> 全局环境变量： <code>/etc/profile</code> <code>/etc/bashrc</code><br> 在全局环境变量文件下面有一个<code>/etc/profile.d</code>目录,在这个目录下可以配置定制的环境变量脚本<br> 当前用户的环境变量和全局环境变量在修改之后，使用source进行更新配置</p><p>下面的设置可根据个人实际情况进行配置，我主要配置于全局变量中</p><h2 id="方式一-配置全局变量文件" tabindex="-1"><a class="header-anchor" href="#方式一-配置全局变量文件" aria-hidden="true">#</a> 方式一，配置全局变量文件</h2><h3 id="一、记录某用户执行命令的时间" tabindex="-1"><a class="header-anchor" href="#一、记录某用户执行命令的时间" aria-hidden="true">#</a> 一、记录某用户执行命令的时间</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> /etc/bashrc
 <span class="token builtin class-name">export</span> <span class="token assign-left variable">HISTTIMEFORMAT</span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable"><span class="token variable">\`</span><span class="token function">whoami</span><span class="token variable">\`</span></span>: | %Y-%m-%d %H:%M:%S | &quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="二、设置历史命令记录条数" tabindex="-1"><a class="header-anchor" href="#二、设置历史命令记录条数" aria-hidden="true">#</a> 二、设置历史命令记录条数</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> /etc/bashrc
 <span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTSIZE</span></span><span class="token operator">=</span><span class="token number">10000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="三、指定不同终端记录的命令放在同一文件并使用追加的方式-这种方式建议在用户的目录下进行" tabindex="-1"><a class="header-anchor" href="#三、指定不同终端记录的命令放在同一文件并使用追加的方式-这种方式建议在用户的目录下进行" aria-hidden="true">#</a> 三、指定不同终端记录的命令放在同一文件并使用追加的方式(这种方式建议在用户的目录下进行)</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> /root/.bashrc
 <span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTFILE</span></span><span class="token operator">=</span>/root/.bash_history  <span class="token comment"># 多个终端记录到一个文件里面</span>
 <span class="token builtin class-name">shopt</span> <span class="token parameter variable">-s</span> histappend      <span class="token comment"># 追加的方式写入文件</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="四、忽略重复的命令-一般不建议使用" tabindex="-1"><a class="header-anchor" href="#四、忽略重复的命令-一般不建议使用" aria-hidden="true">#</a> 四、忽略重复的命令，一般不建议使用</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> /etc/profile
 <span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTCONTROL</span></span><span class="token operator">=</span>ignoredups

<span class="token comment">### </span>
<span class="token environment constant">HISTCONTROL</span>：控制命令历史记录
<span class="token assign-left variable"><span class="token environment constant">HISTCONTROL</span></span><span class="token operator">=</span>ignoredups：忽略连续重复的命令。
<span class="token assign-left variable"><span class="token environment constant">HISTCONTROL</span></span><span class="token operator">=</span>ignorespace：忽略以空白字符开头的命令。
<span class="token assign-left variable"><span class="token environment constant">HISTCONTROL</span></span><span class="token operator">=</span>ignoreboth：同时忽略以上两种。
<span class="token assign-left variable"><span class="token environment constant">HISTCONTROL</span></span><span class="token operator">=</span>erasedups：忽略所有历史命令中的重复命令。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="五、实时写入" tabindex="-1"><a class="header-anchor" href="#五、实时写入" aria-hidden="true">#</a> 五、实时写入</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> /etc/bashrc
 <span class="token builtin class-name">export</span> <span class="token assign-left variable">PROMPT_COMMAND</span><span class="token operator">=</span><span class="token string">&#39;history -a&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="六、设置记录历史命令文件的条数" tabindex="-1"><a class="header-anchor" href="#六、设置记录历史命令文件的条数" aria-hidden="true">#</a> 六、设置记录历史命令文件的条数</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> /etc/bashrc
 <span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTFILESIZE</span></span><span class="token operator">=</span><span class="token number">10000</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="方法二-配置脚本-放入-etc-profile" tabindex="-1"><a class="header-anchor" href="#方法二-配置脚本-放入-etc-profile" aria-hidden="true">#</a> 方法二“配置脚本，放入/etc/profile</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment">#history</span>
<span class="token assign-left variable">USER_IP</span><span class="token operator">=</span><span class="token variable"><span class="token variable">\`</span><span class="token function">who</span> <span class="token parameter variable">-u</span> am i <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span>/dev/null<span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;{print $NF}&#39;</span><span class="token operator">|</span><span class="token function">sed</span> <span class="token parameter variable">-e</span> <span class="token string">&#39;s/[()]//g&#39;</span><span class="token variable">\`</span></span>
<span class="token assign-left variable">HISTDIR</span><span class="token operator">=</span>/usr/share/.history

<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token parameter variable">-z</span> <span class="token variable">$USER_IP</span> <span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>
 <span class="token assign-left variable">USER_IP</span><span class="token operator">=</span><span class="token variable"><span class="token variable">\`</span><span class="token function">hostname</span><span class="token variable">\`</span></span>
<span class="token keyword">fi</span>

<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token operator">!</span> <span class="token parameter variable">-d</span> <span class="token variable">$HISTDIR</span> <span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>
 <span class="token function">mkdir</span> <span class="token parameter variable">-p</span> <span class="token variable">$HISTDIR</span>
 <span class="token function">chmod</span> <span class="token number">777</span> <span class="token variable">$HISTDIR</span>
<span class="token keyword">fi</span>

<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token operator">!</span> <span class="token parameter variable">-d</span> <span class="token variable">$HISTDIR</span>/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span> <span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>
 <span class="token function">mkdir</span> <span class="token parameter variable">-p</span> <span class="token variable">$HISTDIR</span>/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span>
 <span class="token function">chmod</span> <span class="token number">300</span> <span class="token variable">$HISTDIR</span>/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span>
<span class="token keyword">fi</span>

<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTSIZE</span></span><span class="token operator">=</span><span class="token number">4000</span>
<span class="token assign-left variable">DT</span><span class="token operator">=</span><span class="token variable"><span class="token variable">\`</span><span class="token function">date</span> +%Y-%m-%d_%H:%M:%S<span class="token variable">\`</span></span>
<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTFILE</span></span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable">$HISTDIR</span>/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span>/<span class="token variable">\${USER_IP}</span>.history.<span class="token variable">$DT</span>&quot;</span>
<span class="token assign-left variable">HISTTIMEFORMAT</span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable"><span class="token variable">\`</span><span class="token function">whoami</span><span class="token variable">\`</span></span>: | %F | %T: |<span class="token variable">\${USER_IP}</span>:&quot;</span> 
<span class="token function">chmod</span> <span class="token number">600</span> <span class="token variable">$HISTDIR</span>/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span>/*.history* <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span>/dev/nul

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="方法三-配置-etc-profile" tabindex="-1"><a class="header-anchor" href="#方法三-配置-etc-profile" aria-hidden="true">#</a> 方法三： 配置/etc/profile</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment">#history</span>
<span class="token assign-left variable">USER_IP</span><span class="token operator">=</span><span class="token variable"><span class="token variable">\`</span><span class="token function">who</span> <span class="token parameter variable">-u</span> am i <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span>/dev/null<span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;{print $NF}&#39;</span><span class="token operator">|</span><span class="token function">sed</span> <span class="token parameter variable">-e</span> <span class="token string">&#39;s/[()]//g&#39;</span><span class="token variable">\`</span></span>
<span class="token assign-left variable">HISTTIMEFORMAT</span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable"><span class="token variable">\`</span><span class="token function">whoami</span><span class="token variable">\`</span></span>: | %F | %T: |<span class="token variable">\${USER_IP}</span>:&quot;</span> 

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="长久记录所有用户操作记录-自定义脚本" tabindex="-1"><a class="header-anchor" href="#长久记录所有用户操作记录-自定义脚本" aria-hidden="true">#</a> 长久记录所有用户操作记录，自定义脚本</h2><h3 id="实现" tabindex="-1"><a class="header-anchor" href="#实现" aria-hidden="true">#</a> 实现</h3><p>针对 /etc/profile.d中脚本的执行方式，自己编写实现记录所有用户操作记录的脚本<code>get_alluser_cmd.sh</code>。将脚本放在<code>/etc/profile.d/</code>文件夹下，并<code>source /etc/profile</code>来进行生效<br> 这个脚本的作用，在用户退出之后会在/tmp/history_bon目录下生成用户名的文件夹，并在该文件夹下生成对应的登录IP以及时间为文件名的用户操作记录文件</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> get_alluser_cmd.sh
<span class="token comment"># 得到用户操作的相关命令</span>

<span class="token comment"># 设置终端显示符</span>
<span class="token comment">#root@[/tmp/history_bon]</span>


<span class="token assign-left variable">user</span><span class="token operator">=</span><span class="token variable"><span class="token variable">\`</span><span class="token function">whoami</span><span class="token variable">\`</span></span>
<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$user</span>&quot;</span> <span class="token operator">==</span> <span class="token string">&quot;root&quot;</span> <span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>
 <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable"><span class="token variable">\`</span><span class="token function">whoami</span><span class="token variable">\`</span></span>@&quot;</span><span class="token string">&#39;[$PWD]#&#39;</span>
<span class="token keyword">else</span>
 <span class="token assign-left variable"><span class="token environment constant">PS1</span></span><span class="token operator">=</span><span class="token string">&quot;<span class="token variable"><span class="token variable">\`</span><span class="token function">whoami</span><span class="token variable">\`</span></span>@&quot;</span><span class="token string">&#39;[$PWD]$&#39;</span>
<span class="token keyword">fi</span>

<span class="token comment"># HISTORY的记录方式是在用户退出后将history中的缓存写入到HISTFILE中，也可以设置实时写入，查看上面的操作</span>

<span class="token function">history</span>
<span class="token assign-left variable">DateTime</span><span class="token operator">=</span><span class="token variable"><span class="token variable">\`</span><span class="token function">date</span> &quot;+%Y-%m-%d %H:%M:%S<span class="token variable">\`</span></span> 

<span class="token comment"># 获取登录用户的IP</span>
<span class="token assign-left variable">USER_IP</span><span class="token operator">=</span><span class="token variable"><span class="token variable">\`</span><span class="token function">who</span> <span class="token parameter variable">-u</span> am i <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span>/dev/null <span class="token operator">|</span> <span class="token function">awk</span> <span class="token string">&#39;{print $NF}&#39;</span> <span class="token operator">|</span> <span class="token function">sed</span> <span class="token parameter variable">-e</span> <span class="token string">&#39;s/[()]//g&#39;</span><span class="token variable">\`</span></span>
<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token string">&quot;<span class="token variable">$USER_IP</span>&quot;</span> <span class="token operator">==</span> <span class="token string">&quot; &quot;</span><span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>
 <span class="token assign-left variable">USER_IP</span><span class="token operator">=</span><span class="token variable"><span class="token variable">\`</span><span class="token function">hostname</span><span class="token variable">\`</span></span>
<span class="token keyword">fi</span>

<span class="token comment"># 创建文件夹并设置权限</span>
<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token operator">!</span> <span class="token parameter variable">-d</span> /tmp/history_bon<span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>
 <span class="token function">mkdir</span> /tmp/history_bon
 <span class="token function">chmod</span> <span class="token number">777</span> /tmp/history_bon
<span class="token keyword">fi</span>
<span class="token keyword">if</span> <span class="token punctuation">[</span> <span class="token operator">!</span> <span class="token parameter variable">-d</span> /tmp/history_bon/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span><span class="token punctuation">]</span><span class="token punctuation">;</span><span class="token keyword">then</span>
 <span class="token function">mkdir</span> /tmp/history_bon/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span>
 <span class="token function">chmod</span> <span class="token number">300</span> /tmp/history_bon/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span>
<span class="token keyword">fi</span>


<span class="token comment"># 设置history可以相关参数</span>
<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTSIZE</span></span><span class="token operator">=</span><span class="token number">8192</span>     <span class="token comment"># 设置历史命令记录条数</span>
<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTFILE</span></span><span class="token operator">=</span><span class="token string">&quot;/tmp/history_bon/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span>/<span class="token variable">\${USER_IP}</span>.history.<span class="token variable">$DateTime</span>&quot;</span>
<span class="token builtin class-name">export</span> <span class="token assign-left variable">HISTTIMEFORMAT</span><span class="token operator">=</span><span class="token string">&quot;%F %T&quot;</span>   <span class="token comment"># 设置历史命令包含时间</span>
<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTFILE</span></span><span class="token operator">=</span>/root/.bash_history  <span class="token comment"># 多个终端记录到一个文件里面</span>
<span class="token builtin class-name">export</span> <span class="token builtin class-name">shopt</span> <span class="token parameter variable">-s</span> histappend    <span class="token comment"># 多个终端追加的方式写入文件</span>
<span class="token builtin class-name">export</span> <span class="token assign-left variable">PROMPT_COMMAND</span><span class="token operator">=</span><span class="token string">&#39;history -a&#39;</span>  <span class="token comment"># 设置实时写入</span>

<span class="token builtin class-name">export</span> <span class="token assign-left variable"><span class="token environment constant">HISTCONTROL</span></span><span class="token operator">=</span>ignoreboth
<span class="token comment">### </span>
<span class="token comment"># HISTCONTROL：控制命令历史记录</span>
<span class="token comment"># HISTCONTROL=ignoredups：忽略连续重复的命令。</span>
<span class="token comment"># HISTCONTROL=ignorespace：忽略以空白字符开头的命令。</span>
<span class="token comment"># HISTCONTROL=ignoreboth：同时忽略以上两种。</span>
<span class="token comment"># HISTCONTROL=erasedups：忽略所有历史命令中的重复命令。</span>

<span class="token comment"># 只有root对该目录下所有文件有读写权限，防止其他用户改动</span>
<span class="token function">chmod</span> <span class="token number">600</span> /tmp/history_bon/<span class="token variable">\${<span class="token environment constant">LOGNAME</span>}</span>/*history* <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span>/dev/null

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,24),l=[p];function i(o,c){return n(),a("div",null,l)}const d=s(t,[["render",i],["__file","history.html.vue"]]);export{d as default};
